import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import { CartProvider } from './context/CartContext';

import Header from './components/Header';
import Login from './components/Login';
import Home from './components/Home';
import VistaCliente from './components/VistaCliente';
import DashboardVendedor from './components/DashboardVendedor';
import Registro from './components/Registro';
import Carrito from './components/Carrito';
import MisPedidosCliente from './components/MisPedidosCliente';

const PrivateRoute = ({ children, roleRequired }) => {
    const { user, isAuthenticated, loading } = useAuth();

    if (loading) return null;

    if (!isAuthenticated) return <Navigate to="/login" replace />;

    // IMPORTANTE: Buscamos 'rol' tal cual está en tu MongoDB Atlas
    const userRole = String(user?.rol || '').toLowerCase().trim();
    const required = roleRequired.toLowerCase().trim();

    console.log(`CHECK_ROUTE: Usuario(${userRole}) -> Requiere(${required})`);

    if (roleRequired && userRole !== required) {
        console.error("DENEGADO: El rol no coincide");
        return <Navigate to="/" replace />;
    }

    return children;
};

const AppRoutes = () => {
    const { user, isAuthenticated } = useAuth();

    return (
        <>
            <Header /> 
            <Routes>
                <Route path="/" element={<Home isLoggedIn={isAuthenticated} userRole={user?.rol} />} />
                <Route path="/login" element={!isAuthenticated ? <Login /> : <Navigate to="/" replace />} />
                <Route path="/registro" element={<Registro />} />

                <Route path="/dashboard" element={
                    <PrivateRoute roleRequired="vendedor">
                        <DashboardVendedor />
                    </PrivateRoute>
                } />

                <Route path="/panel-cliente" element={
                    <PrivateRoute roleRequired="cliente">
                        <VistaCliente />
                    </PrivateRoute>
                } />

                <Route path="/carrito" element={
                    <PrivateRoute roleRequired="cliente">
                        <Carrito />
                    </PrivateRoute>
                } />

                <Route path="/mis-pedidos" element={
                    <PrivateRoute roleRequired="cliente">
                        <MisPedidosCliente />
                    </PrivateRoute>
                } />

                <Route path="*" element={<Navigate to="/" replace />} />
            </Routes>
        </>
    );
};

function App() {
    return (
        <AuthProvider>
            <CartProvider>
                <Router>
                    <AppRoutes />
                </Router>
            </CartProvider>
        </AuthProvider>
    );
}

export default App;
